#!/usr/bin/env python3
"""Regenerate admin-app module split files (self-contained)."""

from __future__ import annotations

import base64
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

FILES: dict[str, bytes] = {
    'src/apps/admin/components/AdminAppComponent.tsx': base64.b64decode('ZXhwb3J0IHsgQWRtaW5BcHBDb21wb25lbnQgfSBmcm9tICIuL2FkbWluLWFwcC9BZG1pbkFwcENvbXBvbmVudCI7Cg=='),
    'src/apps/admin/components/admin-app/adminImportStatus.ts': base64.b64decode(''),
    'src/apps/admin/components/admin-app/AdminRestrictedView.tsx': base64.b64decode(''),
    'src/apps/admin/components/admin-app/AdminAppDialogs.tsx': base64.b64decode(''),
    'src/apps/admin/components/admin-app/AdminToolbar.tsx': base64.b64decode(''),
    'src/apps/admin/components/admin-app/AdminImportStatusBar.tsx': base64.b64decode(''),
    'src/apps/admin/components/admin-app/AdminUsersView.tsx': base64.b64decode(''),
    'src/apps/admin/components/admin-app/AdminSongsView.tsx': base64.b64decode(''),
    'src/apps/admin/components/admin-app/AdminRoomMessagesView.tsx': base64.b64decode(''),
    'src/apps/admin/components/admin-app/AdminScrollContent.tsx': base64.b64decode(''),
    'src/apps/admin/components/admin-app/AdminStatusBar.tsx': base64.b64decode(''),
    'src/apps/admin/components/admin-app/AdminMainPane.tsx': base64.b64decode(''),
    'src/apps/admin/components/admin-app/AdminAppComponent.tsx': base64.b64decode(''),
}


def main() -> None:
    for rel, data in FILES.items():
        p = ROOT / rel
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(data)
    print(
        f"Wrote {len(FILES)} files under {ROOT / "src/apps/admin/components"}",
    )


if __name__ == "__main__":
    main()
